(function(w){"use strict";const ID="work";function compute(x){const f=Number(x.force),d=Number(x.distance),a=Number(x.angle);if(!Number.isFinite(f)||!Number.isFinite(d)||!Number.isFinite(a))return{error:"힘·거리·각도를 입력해 주세요."};return{value:f*d*Math.cos(a*Math.PI/180)}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>힘 (N)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>이동 거리 (m)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>힘과 이동 방향의 각도 (°)</label><input class="hm-calc-input" inputmode="decimal" value="0"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">일 계산</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({force:api.parseNumber(inputs[0].value),distance:api.parseNumber(inputs[1].value),angle:api.parseNumber(inputs[2].value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("일",`${api.formatNumber(r.value,8)} J`,`W = Fd cosθ`));});}
w.HM_CALC.register(ID,{compute,render});})(window);
